// ============================================================
// API HELPERS
// ============================================================
async function saveClick({ label, platform }) {
  try {
    await fetch("/api/save-click", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        label,
        platform,
        device: /Mobi|Android/i.test(navigator.userAgent) ? "mobile" : "desktop",
      }),
    });
  } catch (e) {
    console.error("API save-click:", e);
  }
}

async function fetchClicks() {
  const res = await fetch("/api/dashboard-clicks", {
    method: "GET",
    credentials: "include",
  });

  if (res.status === 401) {
    return { unauthorized: true, data: [] };
  }

  if (!res.ok) {
    throw new Error("Erro ao buscar cliques");
  }

  const data = await res.json();
  return { unauthorized: false, data };
}

async function loginDashboard(password) {
  const res = await fetch("/api/login", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    credentials: "include",
    body: JSON.stringify({ password }),
  });

  if (!res.ok) {
    return false;
  }

  return true;
}

async function logoutDashboard() {
  try {
    await fetch("/api/logout", {
      method: "POST",
      credentials: "include",
    });
  } catch (e) {
    console.error("API logout:", e);
  }
}

