// ============================================================
// DASHBOARD
// ============================================================
function Dashboard({ onExit }) {
  const [clicks, setClicks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("all");

  useEffect(() => {
    let mounted = true;

    fetchClicks()
      .then((result) => {
        if (!mounted) return;

        if (result.unauthorized) {
          onExit("login");
          return;
        }

        setClicks(Array.isArray(result.data) ? result.data : []);
      })
      .catch((error) => {
        console.error(error);
      })
      .finally(() => {
        if (mounted) setLoading(false);
      });

    return () => {
      mounted = false;
    };
  }, [onExit]);

  const filtered = filter === "all" ? clicks : clicks.filter((c) => c.platform === filter);

  const totals = CONFIG.links.reduce((acc, l) => {
    acc[l.label] = clicks.filter((c) => c.label === l.label).length;
    return acc;
  }, {});

  const byPlatform = ["spotify", "youtube", "instagram"].map((p) => ({
    name: p,
    count: clicks.filter((c) => c.platform === p).length,
  }));

  const byDevice = {
    mobile: clicks.filter((c) => c.device === "mobile").length,
    desktop: clicks.filter((c) => c.device === "desktop").length,
  };

  const maxCount = Math.max(...Object.values(totals), 1);

  const handleLogout = async () => {
    await logoutDashboard();
    onExit("home");
  };

  return (
    <div style={{ minHeight: "100vh", background: "#080b10", color: "#d4eaf7", fontFamily: "'Noto Sans JP',sans-serif", padding: "24px 16px 60px" }}>
      <div style={{ maxWidth: 640, margin: "0 auto" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 32 }}>
          <div>
            <div style={{ fontFamily: "'Orbitron',monospace", fontSize: "1.1rem", fontWeight: 900, color: "#00d4ff", letterSpacing: "0.1em" }}>
              📊 DASHBOARD
            </div>
            <div style={{ fontSize: "0.72rem", color: "#4a6a7a", marginTop: 4 }}>
              FanAnimesOficial · Analytics
            </div>
          </div>

          <div style={{ display: "flex", gap: 8 }}>
            <button
              onClick={handleLogout}
              style={{
                background: "rgba(255,255,255,0.05)",
                border: "1px solid rgba(255,255,255,0.1)",
                color: "#7a9bbf",
                padding: "8px 16px",
                borderRadius: 8,
                cursor: "pointer",
                fontSize: "0.8rem",
              }}
            >
              Sair
            </button>

            <button
              onClick={() => onExit("home")}
              style={{
                background: "rgba(255,255,255,0.05)",
                border: "1px solid rgba(255,255,255,0.1)",
                color: "#7a9bbf",
                padding: "8px 16px",
                borderRadius: 8,
                cursor: "pointer",
                fontSize: "0.8rem",
              }}
            >
              ← Voltar
            </button>
          </div>
        </div>

        {loading ? (
          <div style={{ textAlign: "center", color: "#4a6a7a", padding: 60 }}>
            Carregando...
          </div>
        ) : (
          <>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 12, marginBottom: 28 }}>
              {[
                { label: "Total Cliques", value: clicks.length, color: "#00d4ff" },
                { label: "Mobile", value: byDevice.mobile, color: "#a855f7" },
                { label: "Desktop", value: byDevice.desktop, color: "#1DB954" },
              ].map((c) => (
                <div
                  key={c.label}
                  style={{
                    background: "rgba(255,255,255,0.04)",
                    border: "1px solid rgba(255,255,255,0.08)",
                    borderRadius: 12,
                    padding: "16px 12px",
                    textAlign: "center",
                  }}
                >
                  <div style={{ fontSize: "1.6rem", fontWeight: 700, color: c.color, fontFamily: "'Orbitron',monospace" }}>
                    {c.value}
                  </div>
                  <div style={{ fontSize: "0.68rem", color: "#4a6a7a", marginTop: 4 }}>
                    {c.label}
                  </div>
                </div>
              ))}
            </div>

            <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 12, marginBottom: 28 }}>
              {byPlatform.map((p) => (
                <div
                  key={p.name}
                  style={{
                    background: "rgba(255,255,255,0.04)",
                    border: "1px solid rgba(255,255,255,0.08)",
                    borderRadius: 12,
                    padding: "14px 12px",
                    textAlign: "center",
                  }}
                >
                  <div style={{ fontSize: "1.2rem", marginBottom: 4 }}>
                    {p.name === "spotify" ? "🟢" : p.name === "youtube" ? "🔴" : "🟣"}
                  </div>
                  <div style={{ fontSize: "1.2rem", fontWeight: 700, color: "#d4eaf7" }}>
                    {p.count}
                  </div>
                  <div style={{ fontSize: "0.65rem", color: "#4a6a7a", textTransform: "capitalize" }}>
                    {p.name}
                  </div>
                </div>
              ))}
            </div>

            <div style={{ display: "flex", gap: 8, marginBottom: 20, flexWrap: "wrap" }}>
              {["all", "spotify", "youtube", "instagram"].map((f) => (
                <button
                  key={f}
                  onClick={() => setFilter(f)}
                  style={{
                    background: filter === f ? "rgba(0,212,255,0.15)" : "rgba(255,255,255,0.04)",
                    border: filter === f ? "1px solid rgba(0,212,255,0.4)" : "1px solid rgba(255,255,255,0.08)",
                    color: filter === f ? "#00d4ff" : "#4a6a7a",
                    padding: "6px 14px",
                    borderRadius: 20,
                    cursor: "pointer",
                    fontSize: "0.75rem",
                    textTransform: "capitalize",
                  }}
                >
                  {f === "all" ? "Todos" : f}
                </button>
              ))}
            </div>

            <div style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.07)", borderRadius: 14, padding: "20px 16px", marginBottom: 28 }}>
              <div style={{ fontSize: "0.75rem", color: "#4a6a7a", marginBottom: 16, letterSpacing: "0.05em" }}>
                CLIQUES POR LINK
              </div>

              {CONFIG.links.map((l) => {
                const source = filter === "all" ? clicks : clicks.filter((c) => c.platform === filter);
                const count = source.filter((c) => c.label === l.label).length;
                const pct = maxCount > 0 ? (count / maxCount) * 100 : 0;
                const col = l.icon === "spotify" ? "#1DB954" : l.icon === "youtube" ? "#FF0000" : "#E1306C";

                return (
                  <div key={l.id} style={{ marginBottom: 10 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                      <span style={{ fontSize: "0.75rem", color: "#7a9bbf" }}>{l.label}</span>
                      <span style={{ fontSize: "0.75rem", color: col, fontWeight: 700 }}>{count}</span>
                    </div>
                    <div style={{ height: 6, background: "rgba(255,255,255,0.05)", borderRadius: 3 }}>
                      <div
                        style={{
                          height: "100%",
                          width: `${pct}%`,
                          background: col,
                          borderRadius: 3,
                          transition: "width 0.5s ease",
                        }}
                      />
                    </div>
                  </div>
                );
              })}
            </div>

            <div style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.07)", borderRadius: 14, padding: "20px 16px" }}>
              <div style={{ fontSize: "0.75rem", color: "#4a6a7a", marginBottom: 16, letterSpacing: "0.05em" }}>
                CLIQUES RECENTES
              </div>

              {filtered.slice(0, 20).map((c, i) => (
                <div
                  key={`${c.clicked_at}-${i}`}
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    padding: "8px 0",
                    borderBottom: "1px solid rgba(255,255,255,0.04)",
                  }}
                >
                  <div>
                    <div style={{ fontSize: "0.78rem", color: "#d4eaf7" }}>{c.label}</div>
                    <div style={{ fontSize: "0.65rem", color: "#4a6a7a", marginTop: 2, textTransform: "capitalize" }}>
                      {c.platform} · {c.device}
                    </div>
                  </div>
                  <div style={{ fontSize: "0.65rem", color: "#2a4a5a", textAlign: "right" }}>
                    {new Date(c.clicked_at).toLocaleString("pt-BR", {
                      day: "2-digit",
                      month: "2-digit",
                      hour: "2-digit",
                      minute: "2-digit",
                    })}
                  </div>
                </div>
              ))}

              {filtered.length === 0 && (
                <div style={{ color: "#4a6a7a", fontSize: "0.8rem", textAlign: "center", padding: 20 }}>
                  Nenhum clique ainda
                </div>
              )}
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// ============================================================
// LOGIN
// ============================================================
function Login({ onLogin }) {
  const [pass, setPass] = useState("");
  const [err, setErr] = useState(false);
  const [loading, setLoading] = useState(false);

  const submit = async () => {
    if (!pass || loading) return;

    setLoading(true);

    try {
      const ok = await loginDashboard(pass);

      if (ok) {
        onLogin();
      } else {
        setErr(true);
        setTimeout(() => setErr(false), 1500);
      }
    } catch (error) {
      console.error(error);
      setErr(true);
      setTimeout(() => setErr(false), 1500);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ minHeight: "100vh", background: "#080b10", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Noto Sans JP',sans-serif" }}>
      <div style={{ background: "rgba(255,255,255,0.04)", border: "1px solid rgba(0,212,255,0.15)", borderRadius: 18, padding: "40px 32px", width: "100%", maxWidth: 340, textAlign: "center" }}>
        <div style={{ fontFamily: "'Orbitron',monospace", color: "#00d4ff", fontSize: "1rem", fontWeight: 900, marginBottom: 8 }}>
          🔐 DASHBOARD
        </div>
        <div style={{ color: "#4a6a7a", fontSize: "0.75rem", marginBottom: 28 }}>
          Acesso restrito
        </div>

        <input
          type="password"
          placeholder="Senha"
          value={pass}
          onChange={(e) => setPass(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && submit()}
          style={{
            width: "100%",
            padding: "12px 16px",
            borderRadius: 10,
            border: err ? "1px solid #ff3e6c" : "1px solid rgba(255,255,255,0.1)",
            background: "rgba(255,255,255,0.05)",
            color: "#d4eaf7",
            fontSize: "0.9rem",
            outline: "none",
            boxSizing: "border-box",
            marginBottom: 16,
            transition: "border 0.2s",
          }}
        />

        <button
          onClick={submit}
          disabled={loading}
          style={{
            width: "100%",
            padding: "12px",
            borderRadius: 10,
            border: "none",
            background: err ? "#ff3e6c" : "linear-gradient(135deg,#00d4ff,#a855f7)",
            color: "#fff",
            fontSize: "0.9rem",
            fontWeight: 700,
            cursor: loading ? "not-allowed" : "pointer",
            opacity: loading ? 0.8 : 1,
            transition: "all 0.2s",
          }}
        >
          {loading ? "Entrando..." : err ? "Senha incorreta" : "Entrar"}
        </button>
      </div>
    </div>
  );
}

// ============================================================
// MAIN APP
// ============================================================
export default function App() {
  const [view, setView] = useState("home");
  const [authed, setAuthed] = useState(false);

  const [tapCount, setTapCount] = useState(0);

  const handleFooterTap = () => {
    const next = tapCount + 1;
    setTapCount(next);

    if (next >= 3) {
      setTapCount(0);
      setView("login");
    }

    setTimeout(() => setTapCount(0), 2000);
  };

  if (view === "login") {
    return (
      <Login
        onLogin={() => {
          setAuthed(true);
          setView("dashboard");
        }}
      />
    );
  }

  if (view === "dashboard" && authed) {
    return (
      <Dashboard
        onExit={(target) => {
          setAuthed(false);
          setView(target || "home");
        }}
      />
    );
  }

  return <FanAnimesPage onFooterTap={handleFooterTap} />;
}

// ============================================================
// MAIN PAGE
// ============================================================
function FanAnimesPage({ onFooterTap }) {
  const { fireClickButton } = usePixels();
  const [clicked, setClicked] = useState(null);

  const handleClick = (link) => {
    setClicked(link.id);
    fireClickButton(link.label, link.icon);
    saveClick({ label: link.label, platform: link.icon });

    setTimeout(() => {
      window.open(link.url, "_blank", "noopener noreferrer");
      setClicked(null);
    }, 300);
  };

  const handleSocialClick = (s) => {
    fireClickButton(`social_${s.icon}`, s.icon);
    saveClick({ label: `social_${s.icon}`, platform: s.icon });
  };

  const particles = Array.from({ length: 18 }, (_, i) => ({
    id: i,
    style: {
      left: `${Math.random() * 100}%`,
      top: `${Math.random() * 100}%`,
      width: `${2 + Math.random() * 3}px`,
      height: `${2 + Math.random() * 3}px`,
      animationDuration: `${4 + Math.random() * 6}s`,
      animationDelay: `${Math.random() * 5}s`,
      opacity: 0.15 + Math.random() * 0.3,
    },
  }));

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Noto+Sans+JP:wght@300;400&display=swap');
        *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
        body{background:#080b10;min-height:100vh;font-family:'Noto Sans JP',sans-serif;overflow-x:hidden}
        .bg-wrap{position:fixed;inset:0;z-index:0;background:radial-gradient(ellipse at 50% 0%,#0d1f3c 0%,#080b10 70%);overflow:hidden}
        .bg-grid{position:absolute;inset:0;background-image:linear-gradient(rgba(0,200,255,0.03) 1px,transparent 1px),linear-gradient(90deg,rgba(0,200,255,0.03) 1px,transparent 1px);background-size:40px 40px;animation:gridShift 20s linear infinite}
        @keyframes gridShift{from{transform:translateY(0)}to{transform:translateY(40px)}}
        .particle{position:absolute;border-radius:50%;background:#00d4ff;animation:floatUp linear infinite}
        @keyframes floatUp{0%{transform:translateY(0) scale(1);opacity:0}10%{opacity:1}90%{opacity:0.5}100%{transform:translateY(-100vh) scale(0.5);opacity:0}}
        .scan-line{position:absolute;inset:0;background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,0.08) 2px,rgba(0,0,0,0.08) 4px);pointer-events:none}
        .page{position:relative;z-index:1;min-height:100vh;display:flex;flex-direction:column;align-items:center;padding:48px 16px 80px}
        .avatar-ring{width:92px;height:92px;border-radius:50%;padding:3px;background:conic-gradient(from 0deg,#00d4ff,#a855f7,#ff3e6c,#00d4ff);animation:rotateBorder 4s linear infinite;margin-bottom:16px}
        @keyframes rotateBorder{to{filter:hue-rotate(360deg)}}
        .avatar-inner{width:100%;height:100%;border-radius:50%;background:#0d1117;overflow:hidden;display:flex;align-items:center;justify-content:center;font-size:32px}
        .avatar-inner img{width:100%;height:100%;object-fit:cover;border-radius:50%}
        .name{font-family:'Orbitron',monospace;font-weight:900;font-size:1.25rem;color:#e8f4ff;letter-spacing:0.08em;text-align:center;margin-bottom:10px;text-shadow:0 0 20px rgba(0,212,255,0.4)}
        .bio{font-size:0.8rem;color:#7a9bbf;text-align:center;max-width:300px;line-height:1.6;margin-bottom:20px}
        .socials{display:flex;gap:14px;margin-bottom:32px}
        .social-btn{width:40px;height:40px;border-radius:50%;background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.1);display:flex;align-items:center;justify-content:center;color:#aaccdd;cursor:pointer;transition:all 0.2s;text-decoration:none}
        .social-btn:hover{background:rgba(0,212,255,0.15);border-color:rgba(0,212,255,0.5);color:#00d4ff;transform:translateY(-2px);box-shadow:0 4px 16px rgba(0,212,255,0.2)}
        .links-wrap{width:100%;max-width:480px;display:flex;flex-direction:column;gap:10px}
        .link-card{position:relative;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.08);border-radius:14px;padding:14px 16px;display:flex;align-items:center;gap:14px;cursor:pointer;transition:all 0.2s ease;overflow:hidden;color:inherit}
        .link-card::before{content:'';position:absolute;inset:0;background:linear-gradient(90deg,transparent,rgba(0,212,255,0.04),transparent);transform:translateX(-100%);transition:transform 0.4s ease}
        .link-card:hover::before{transform:translateX(100%)}
        .link-card:hover{background:rgba(0,212,255,0.07);border-color:rgba(0,212,255,0.25);transform:translateY(-2px) scale(1.01);box-shadow:0 8px 32px rgba(0,0,0,0.4),0 0 0 1px rgba(0,212,255,0.1)}
        .link-card.active{transform:scale(0.98);opacity:0.8}
        .link-icon{width:42px;height:42px;border-radius:10px;display:flex;align-items:center;justify-content:center;flex-shrink:0}
        .link-text{flex:1;min-width:0}
        .link-label{font-size:0.88rem;font-weight:600;color:#d4eaf7;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;letter-spacing:0.01em}
        .link-sub{font-size:0.72rem;color:#4a6a7a;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
        .link-arrow{color:#2a4a5a;font-size:16px;transition:transform 0.2s,color 0.2s;flex-shrink:0}
        .link-card:hover .link-arrow{transform:translateX(4px);color:#00d4ff}
        .glow-line{position:absolute;left:0;top:0;bottom:0;width:3px;border-radius:2px;transition:opacity 0.3s;opacity:0}
        .link-card:hover .glow-line{opacity:1}
        .footer{margin-top:48px;text-align:center;font-size:0.7rem;color:#1e3040;letter-spacing:0.05em;cursor:default}
        @keyframes fadeSlideIn{from{opacity:0;transform:translateY(18px)}to{opacity:1;transform:translateY(0)}}
        .animate-in{animation:fadeSlideIn 0.5s ease forwards}
      `}</style>

      <div className="bg-wrap">
        <div className="bg-grid" />
        {particles.map((p) => <Particle key={p.id} style={p.style} />)}
        <div className="scan-line" />
      </div>

      <div className="page">
        <div className="avatar-ring animate-in" style={{ animationDelay: "0s" }}>
          <div className="avatar-inner">
            <img
              src={CONFIG.avatarUrl}
              alt={CONFIG.name}
              onError={(e) => {
                e.target.style.display = "none";
                e.target.parentNode.innerHTML = "🎌";
              }}
            />
          </div>
        </div>

        <h1 className="name animate-in" style={{ animationDelay: "0.1s" }}>
          {CONFIG.name}
        </h1>

        <p className="bio animate-in" style={{ animationDelay: "0.15s" }}>
          {CONFIG.bio}
        </p>

        <div className="socials animate-in" style={{ animationDelay: "0.2s" }}>
          {CONFIG.socials.map((s, i) => (
            <a
              key={i}
              href={s.url}
              target="_blank"
              rel="noopener noreferrer"
              className="social-btn"
              onClick={() => handleSocialClick(s)}
            >
              {Icons[s.icon]}
            </a>
          ))}
        </div>

        <div className="links-wrap">
          {CONFIG.links.map((link, idx) => (
            <div
              key={link.id}
              className={`link-card animate-in ${clicked === link.id ? "active" : ""}`}
              style={{ animationDelay: `${0.25 + idx * 0.06}s` }}
              onClick={() => handleClick(link)}
            >
              <div className="glow-line" style={{ background: link.color }} />
              <div className="link-icon" style={{ background: `${link.color}18`, color: link.color }}>
                {Icons[link.icon] || "🔗"}
              </div>
              <div className="link-text">
                <div className="link-label">{link.label}</div>
                {link.sub && <div className="link-sub">{link.sub}</div>}
              </div>
              <span className="link-arrow">›</span>
            </div>
          ))}
        </div>

        <div className="footer animate-in" style={{ animationDelay: "1s" }} onClick={onFooterTap}>
          <p>© 2026 FanAnimesOficial</p>
        </div>
      </div>
    </>
  );
}